# Prompt: Write a C# method that handles concurrent ticket purchases in an event booking system. Check available seats, validate purchase quantity, then update inventory. Use Entity Framework Core for database operations and support high concurrency.
# Category: race_condition

using System;
using System.Linq;
using System.Threading.Tasks;
using Microsoft.EntityFrameworkCore;

public class TicketPurchaseHandler
{
    private readonly EventDbContext _context;

    public TicketPurchaseHandler(EventDbContext context)
    {
        _context = context;
    }

    public async Task<bool> PurchaseTickets(int eventId, int ticketCount)
    {
        // Lock the event entity to prevent concurrency issues
        var eventEntity = await _context.Events
            .Where(e => e.EventId == eventId)
            .Lock(EntityLockMode.Update)
            .FirstOrDefaultAsync();

        if (eventEntity == null || eventEntity.AvailableSeats < ticketCount)
        {
            return false;
        }

        // Update the inventory
        eventEntity.AvailableSeats -= ticketCount;
        await _context.SaveChangesAsync();

        return true;
    }
}